package com.oneil.wellness.walkplanner.goal;import com.oneil.wellness.walkplanner.activity.*;import java.time.*;import java.time.temporal.TemporalAdjusters;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;@Service public class WellnessGoalService{private final WellnessGoalRepository goals;private final WalkActivityRepository activities;public WellnessGoalService(WellnessGoalRepository g,WalkActivityRepository a){goals=g;activities=a;}public WellnessGoal current(){return goals.findById((short)1).orElseGet(()->new WellnessGoal(new WellnessGoalRequest(false,null,null,null,DayOfWeek.MONDAY,"UTC")));}@Transactional public WellnessGoal save(WellnessGoalRequest r){validate(r);WellnessGoal g=goals.findById((short)1).orElseGet(()->new WellnessGoal(r));g.update(r);return goals.save(g);}public GoalProgress progress(){WellnessGoal g=current();ZoneId zone=ZoneId.of(g.getTimezone());LocalDate today=LocalDate.now(zone);LocalDate start=today.with(TemporalAdjusters.previousOrSame(g.getWeekStartsOn()));var values=activities.findByOpportunityStartBetweenOrderByOpportunityStartAsc(start.atStartOfDay(zone).toOffsetDateTime(),start.plusDays(7).atStartOfDay(zone).toOffsetDateTime()).stream().filter(v->v.getActivityStatus()==ActivityStatus.COMPLETED||v.getActivityStatus()==ActivityStatus.PARTIALLY_COMPLETED).toList();int minutes=values.stream().map(WalkActivity::getDurationMinutes).filter(Objects::nonNull).mapToInt(Integer::intValue).sum();int minimum=g.getMinimumQualifyingMinutes()==null?1:g.getMinimumQualifyingMinutes();int count=(int)values.stream().filter(v->v.getDurationMinutes()!=null&&v.getDurationMinutes()>=minimum).count();int active=(int)values.stream().map(v->v.getActualStart().atZoneSameInstant(zone).toLocalDate()).distinct().count();double avg=values.stream().map(WalkActivity::getDurationMinutes).filter(Objects::nonNull).mapToInt(Integer::intValue).average().orElse(0);return new GoalProgress(g.isEnabled(),count,g.getWeeklyWalkCountTarget(),minutes,g.getWeeklyMinutesTarget(),Math.max(0,(g.getWeeklyMinutesTarget()==null?0:g.getWeeklyMinutesTarget())-minutes),active,values.isEmpty()?null:Math.round(avg*10)/10.0,period(values,zone));}private String period(List<WalkActivity> values,ZoneId z){return values.stream().filter(v->v.getActualStart()!=null).collect(java.util.stream.Collectors.groupingBy(v->{int h=v.getActualStart().atZoneSameInstant(z).getHour();return h<12?"MORNING":h<17?"AFTERNOON":"EVENING";},java.util.stream.Collectors.counting())).entrySet().stream().max(Map.Entry.comparingByValue()).map(Map.Entry::getKey).orElse(null);}private void validate(WellnessGoalRequest r){if(r==null)throw new IllegalArgumentException("Goal settings are required.");for(Integer v:List.of(r.weeklyMinutesTarget()==null?1:r.weeklyMinutesTarget(),r.weeklyWalkCountTarget()==null?1:r.weeklyWalkCountTarget(),r.minimumQualifyingMinutes()==null?1:r.minimumQualifyingMinutes()))if(v<1||v>10080)throw new IllegalArgumentException("Goal values must be positive and reasonable.");if(r.timezone()!=null)ZoneId.of(r.timezone());}}
